class Solution:
    def countPairs(self, words):
        n = len(words)
        def similar(s, t):
            if len(s) != len(t):
                return False
            for k in range(26):
                ok = True
                for a, b in zip(s, t):
                    if (ord(a) - 97 + k) % 26 != ord(b) - 97:
                        ok = False
                        break
                if ok:
                    return True
            return False
        count = 0
        for i in range(n):
            for j in range(i + 1, n):
                if similar(words[i], words[j]):
                    count += 1
        return count

