class Solution:
    def countPairs(self, words):
        from collections import defaultdict
        groups = defaultdict(int)
        for w in words:
            shift = ord(w[0]) - 97
            norm = tuple((ord(c) - 97 - shift) % 26 for c in w)
            groups[norm] += 1
        total = 0
        for c in groups.values():
            total += c * (c - 1) // 2
        return total

