var countPairs = function(words) {
    const groups = new Map();
    for (const w of words) {
        const shift = w.charCodeAt(0) - 97;
        let norm = '';
        for (let i = 0; i < w.length; i++) {
            const v = ((w.charCodeAt(i) - 97 - shift) % 26 + 26) % 26;
            norm += String.fromCharCode(97 + v);
        }
        groups.set(norm, (groups.get(norm) || 0) + 1);
    }
    let total = 0;
    for (const c of groups.values()) {
        total += (c * (c - 1)) / 2;
    }
    return total;
};
